`).map((f,A)=>{const c=f,L=c.startsWith("import ")||c.startsWith("from ")||c.startsWith("d(")||c.startsWith("cos(")||c.startsWith("dot(")||c.startsWith("score(")||c.startsWith("Recall@")||c.startsWith("    ")||c.startsWith("np.")||c.startsWith("torch")||c.startsWith("# ")||c.startsWith("SELECT")||c.startsWith("d =")||c.startsWith("L2")||c.startsWith("|")||c.startsWith("Score(")||c.startsWith("RRF")||c.startsWith("L_")||c.startsWith("binary(")||c.startsWith("q(")||c.startsWith("hamming(")||c.startsWith("model")||c.startsWith("train_"),z=c.startsWith("import ")||c.startsWith("from ")||c.startsWith("d(")||c.startsWith("# ")||c.startsWith("SELECT")||c.startsWith("score(")||c.startsWith("|")||c.startsWith("Score(")||c.startsWith("RRF")||c.startsWith("L_")||c.startsWith("binary(")||c.startsWith("q(")||c.startsWith("hamming(")||c.startsWith("model")||c.startsWith("train_");if(L)return a.jsx("div",{style:{fontFamily:"'JetBrains Mono', monospace",fontSize:11.5,color:"#D4D4D8",background:"#1C1C2E",padding:z?"10px 14px 2px":"2px 14px",whiteSpace:"pre-wrap",lineHeight:1.7,borderRadius:z?"6px 6px 0 0":0,marginTop:z?10:0},children:c},A);if(c==="")return a.jsx("div",{style:{height:8}},A);const Y=c.split(/\*\*(.*?)\*\*/g);return a.jsx("p",{style:{fontSize:13.5,lineHeight:1.75,color:"#3a3a3a",marginBottom:2},children:Y.map((p,S)=>S%2===1?a.jsx("strong",{style:{color:"#1a1a1a",fontWeight:600},children:p},S):a.jsx("span",{children:p},S))},A)});return a.jsxs("div",{style:{fontFamily:"'Source Serif 4', Georgia, serif",background:"#F5F3EE",minHeight:l?"auto":"100vh",color:"#1a1a1a"},children:[a.jsx("style",{children:`
